/**
 * 
 * @export
 * @interface CouponRequestDto
 */
export interface CouponRequestDto {
    /**
     * The name of the coupon. This field represents the official name or identifier for the coupon, and it cannot be empty.
     * @type {string}
     * @memberof CouponRequestDto
     */
    'name': string;
    /**
     * A brief description of the coupon providing additional context about the discount or promotion.
     * @type {string}
     * @memberof CouponRequestDto
     */
    'description'?: string;
    /**
     * The unique code that users enter to apply the coupon. This code must be unique and cannot be empty.
     * @type {string}
     * @memberof CouponRequestDto
     */
    'couponCode': string;
    /**
     * Indicates whether the coupon is currently active and can be applied. The default value is false.
     * @type {boolean}
     * @memberof CouponRequestDto
     */
    'isActive'?: boolean;
    /**
     * The maximum number of times this coupon can be applied across all users. If not specified, the coupon has no total usage limit.
     * @type {number}
     * @memberof CouponRequestDto
     */
    'timesCanBeAppliedTotal'?: number;
    /**
     * The maximum number of times a single user can apply this coupon. If not specified, there is no per-user usage limit.
     * @type {number}
     * @memberof CouponRequestDto
     */
    'timesCanBeAppliedPerUser'?: number;
    /**
     * When enabled, this coupon will not apply to products that already have a discount price. This prevents stacking coupons on already discounted items.
     * @type {boolean}
     * @memberof CouponRequestDto
     */
    'excludeFromDiscountedProducts'?: boolean;
    /**
     * The date and time from which the coupon becomes valid and can be applied.
     * @type {string}
     * @memberof CouponRequestDto
     */
    'startDate': string;
    /**
     * The date and time after which the coupon expires and can no longer be applied.
     * @type {string}
     * @memberof CouponRequestDto
     */
    'endDate': string;
    /**
     * An array of unique identifiers of the price policies to which this coupon applies.
     * @type {Array<string>}
     * @memberof CouponRequestDto
     */
    'appliedOnPricePolicies'?: Array<string>;
    /**
     * An array of rules that define the discount logic for this coupon, including the product IDs, actions, durations, discount type, and value.
     * @type {Array<RuleRequestDto>}
     * @memberof CouponRequestDto
     */
    'rules': Array<RuleRequestDto>;
}
